import numpy as np

def select_next_node(current_node, destination_node, unvisited_nodes, distance_matrix):
    shortest_distance = float('inf')
    next_node = None

    for node in unvisited_nodes:
        if distance_matrix[current_node][node] < shortest_distance:
            shortest_distance = distance_matrix[current_node][node]
            next_node = node
        elif distance_matrix[current_node][node] == shortest_distance:
            if np.random.randint(2) == 0:
                next_node = node

    return next_node
